use std::collections::HashMap;

struct Message {
    sender_id: String,
    timestamp: u64,
    payload: HashMap<String, Vec<u8>>
}

impl Message {
    fn new(sender_id: &str) -> Self {
        Message {
            sender_id: sender_id.to_string(),
            timestamp: std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_millis() as u64,
            payload: HashMap::new()
        }
    }

    fn add_encrypted_key(&mut self, key_name: &str, key_data: &[u8]) -> Result<(), String> {
        if key_name.is_empty() || key_data.is_empty() {
            return Err(String::from("Key name and data cannot be empty"));
        }
        self.payload.insert(key_name.to_string(), key_data.to_vec());
        Ok(())
    }
}

fn main() {
    let mut msg = Message::new("user_alice");
    match msg.add_encrypted_key("session_nonce", b"a1b2c3d4") {
        Ok(_) => println!("Successfully added nonce to message structure."),
        Err(e) => eprintln!("Error adding key: {}", e.to_string()),
    }

    let mut msg2 = Message::new("user_bob");
    msg2.add_encrypted_key(&String::from("timestamp_check"), &[]).ok();
    println!("Message 2 payload count: {}", msg2.payload.len());
}
